import React, { useState } from "react";
import HomePage from "./HomePage";

// Trang FriendList
const FriendList = () => {
  const friends = ["Nguyễn Văn A", "Nguyễn Văn B", "Nguyễn Văn C"];
  const suggestions = ["Trần Thị X", "Lê Văn Y", "Phạm Thị Z"];

  return (
    <div className="flex gap-6">
      <div className="flex-1 flex flex-col gap-4">
        <h2 className="text-2xl font-bold mb-3">Danh sách bạn bè</h2>
        {friends.map((name, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#A2D3FF] p-3 rounded-lg"
          >
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
              className="w-[90px] h-20 object-fill"
            />
            <span className="text-black text-2xl flex-1">{name}</span>
            <button className="bg-white px-3 py-1 rounded-lg">Delete</button>
            <button className="bg-[#F6FEFF] px-3 py-1 rounded-lg">Follow</button>
          </div>
        ))}
      </div>
      <div className="w-[300px] flex flex-col gap-3">
        <h2 className="text-2xl font-bold mb-3">Gợi ý kết bạn</h2>
        {suggestions.map((name, idx) => (
          <div
            key={idx}
            className="flex items-center gap-4 bg-[#F0F8FF] p-3 rounded-lg"
          >
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/kw5jvhez_expires_30_days.png"
              className="w-[60px] h-16 object-fill"
            />
            <span className="flex-1 text-black text-xl">{name}</span>
            <button className="bg-[#88BCF8] text-white px-3 py-1 rounded-lg">
              Thêm bạn
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

// App chính
export default function App() {
  const [currentPage, setCurrentPage] = useState("home");
  const [input1, onChangeInput1] = useState("");

  return (
    <div className="flex">

      {/* Sidebar cố định */}
      <div className="fixed top-[140px] left-0 flex flex-col items-center bg-[#88BCF8] w-[88px] py-[25px] px-[23px] gap-[30px]">
        <img
          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"
          className="w-[42px] h-[42px] cursor-pointer"
          onClick={() => setCurrentPage("home")}
        />
        <img
          src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/qfk5vizv_expires_30_days.png"
          className="w-[42px] h-[37px] cursor-pointer"
          onClick={() => setCurrentPage("friends")}
        />
      </div>

      <div className="flex-1 ml-[88px]">

        {/* Header cố định */}
        <div className="fixed top-0 left-[88px] right-0 flex items-center justify-between bg-[#88BCF8] py-3 px-6 z-50">
          <div className="flex items-center flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/iitooitd_expires_30_days.png"
              className="w-[120px] h-[110px] object-fill"
            />
          </div>
          <div className="flex-1 mx-6 max-w-[600px]">
            <input
              placeholder="Nhập để tìm kiếm"
              value={input1}
              onChange={(e) => onChangeInput1(e.target.value)}
              className="text-black bg-[#F6FEFF] text-base w-full py-2 px-5 rounded-[50px] border-0"
            />
          </div>
          <div className="flex items-center gap-4 flex-shrink-0">
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/ta15udsi_expires_30_days.png"
              className="w-[50px] h-[38px]"
              alt="search-icon"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/pt1vc4hr_expires_30_days.png"
              className="w-[47px] h-[69px]"
              alt="settings-icon"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/l63q73r0_expires_30_days.png"
              className="w-[42px] h-[42px]"
              alt="profile-icon"
            />
            <img
              src="https://storage.googleapis.com/tagjs-prod.appspot.com/v1/qdvbauSaaE/rykqncqm_expires_30_days.png"
              className="w-[63px] h-[63px]"
              alt="message-icon"
            />
          </div>
        </div>

        {/* Nội dung trang */}
        <div className="mt-[140px] p-6">
          {currentPage === "home" && (
            <HomePage input1={input1} onChangeInput1={onChangeInput1} />
          )}
          {currentPage === "friends" && <FriendList />}
        </div>
      </div>
    </div>
  );
}
